const THEME_KEY = "kv-portfolio-theme";

const applyTheme = (theme) => {
  const root = document.documentElement;
  if (theme === "dark") {
    root.classList.add("dark");
  } else {
    root.classList.remove("dark");
  }
};

const getPreferredTheme = () => {
  const stored = localStorage.getItem(THEME_KEY);
  if (stored === "light" || stored === "dark") {
    return stored;
  }

  const prefersDark = window.matchMedia("(prefers-color-scheme: dark)");
  return prefersDark.matches ? "dark" : "light";
};

const updateToggleIcon = (theme) => {
  const toggle = document.getElementById("theme-toggle");
  if (!toggle) return;

  const icon = toggle.querySelector("[data-icon]");
  const label = toggle.querySelector("[data-label]");
  const isDark = theme === "dark";

  if (icon) {
    icon.textContent = isDark ? "🌙" : "☀️";
  }

  if (label) {
    label.textContent = isDark ? "Switch to light mode" : "Switch to dark mode";
  }

  toggle.setAttribute("aria-pressed", isDark.toString());
};

const toggleTheme = () => {
  const current = document.documentElement.classList.contains("dark")
    ? "dark"
    : "light";
  const next = current === "dark" ? "light" : "dark";
  localStorage.setItem(THEME_KEY, next);
  applyTheme(next);
  updateToggleIcon(next);
};

const setupSmoothScroll = () => {
  document.querySelectorAll("[data-scroll-to]").forEach((trigger) => {
    trigger.addEventListener("click", (event) => {
      event.preventDefault();
      const targetId = trigger.getAttribute("data-scroll-to");
      if (!targetId) return;
      const target = document.getElementById(targetId);
      if (!target) return;
      target.scrollIntoView({ behavior: "smooth", block: "start" });
      if (typeof target.focus === "function") {
        try {
          target.focus({ preventScroll: true });
        } catch (error) {
          target.focus();
        }
      }
    });
  });
};

window.addEventListener("DOMContentLoaded", () => {
  const preferred = getPreferredTheme();
  applyTheme(preferred);
  updateToggleIcon(preferred);

  const toggleElement = document.getElementById("theme-toggle");
  if (toggleElement) {
    toggleElement.addEventListener("click", toggleTheme);
  }

  setupSmoothScroll();
});
